# Let me use nm on the debug file to find function names, and also try 
# addr2line with the executable + debug info linked
# First let's check the symbol table for the addresses that returned $d.147
nm --defined-only /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | sort | head -5
echo "---"
# Find the function containing 0x2f4b20
nm --defined-only /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | sort | awk '
  BEGIN { prev_addr=""; prev_name="" }
  {
    addr = strtonum("0x"$1)
    if (prev_addr != "" && addr > target && prev_addr <= target) {
      printf "0x%x is in %s (at 0x%x + 0x%x)\n", target, prev_name, prev_addr, target-prev_addr
    }
    prev_addr = addr; prev_name = $3
  }
' target=$((0x2f4b20))
echo "---"
# Use objdump to find the function containing these addresses  
for addr in 0x2f4b20 0x2f4c84 0x2c1a40 0x16de04; do
  echo -n "Address $addr -> "
  nm --defined-only -S /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | sort | awk -v target="$addr" '
    {
      a = strtonum("0x"$1)
      t = strtonum(target)
      if ($2 != "") {
        s = strtonum("0x"$2)
      } else {
        s = 0
      }
      if (a <= t && (s == 0 || a + s > t) && $3 ~ /^[A-Za-z_]/) {
        printf "%s (0x%x+0x%x)\n", $4 ? $4 : $3, a, t-a
      }
    }
  '
done

